class Solution {
public:
    int maxScore(vector<int>& nums) {
        int n = nums.size() / 2;
        vector<int> memo(1 << n);
        function<int(int, vector<int>)> dfs = [&](int mask, vector<int> nums) {
            if (nums.empty()) return 0;
            if (memo[mask] != 0) return memo[mask];
            int res = 0;
            for (int i = 0; i < nums.size(); i++) {
                for (int j = i + 1; j < nums.size(); j++) {
                    int x = nums[i], y = nums[j];
                    vector<int> next;
                    for (int k = 0; k < nums.size(); k++) {
                        if (k != i && k != j) next.push_back(nums[k]);
                    }
                    res = max(res, gcd(x, y) + dfs(mask, next));
                }
            }
            memo[mask] = res;
            return res;
        };
        return dfs(0, nums);
    }
    int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
};

